-- -----------------------------------------------------
-- procedure Reporte_Listado_Articulos
-- -----------------------------------------------------

USE `bd_inventario`;
DROP procedure IF EXISTS `bd_inventario`.`Reporte_Listado_Articulos`;

DELIMITER $$
USE `bd_inventario`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `Reporte_Listado_Articulos`()
BEGIN
SELECT A.id_articulo as ID_ART,
    A.nom_articulo as Nombre_Art,
    A.Precio_Venta_Art as Precio_Venta,
    I.id_insumo as Num_Insumo,
    I.Nom_Insumo as Nombre_Ins,
    I.Punto_Reorden_Ins as Reorden,
    I.Inventario_Ins as Inventario,
    P.Nom_Proveedor as Proveedor,
    I.Precio_Compra_Ins as Precio_Ins
    FROM articulos A, Insumos I, Proveedores P
    WHERE I.id_insumo = A.Id_insumo_Art AND 
	P.Id_Proveedor = I.Id_Proveedor_Ins
    ORDER BY A.Id_Articulo ASC, I.id_insumo ASC;
END$$

