USE `bd_inventario`$$
DROP TRIGGER IF EXISTS `bd_inventario`.`articulos_BEFORE_INSERT` $$
USE `bd_inventario`$$
CREATE
DEFINER=`root`@`localhost`
TRIGGER `bd_inventario`.`articulos_BEFORE_INSERT`
BEFORE INSERT ON `bd_inventario`.`articulos`
FOR EACH ROW
BEGIN
/*Checa que el Articulo No tenga mas de 10 Insumos Asignados*/
    IF (	SELECT COUNT(*)
				FROM Articulos
				WHERE Id_Articulo = new.id_Articulo
				GROUP BY Id_Articulo)>10 THEN
        SIGNAL SQLSTATE "45000"
        SET MESSAGE_TEXT = "No se puede Agregar mas de 10 Insumos por Articulo";
	END IF;
END$$


USE `bd_inventario`$$
DROP TRIGGER IF EXISTS `bd_inventario`.`insumos_BEFORE_INSERT` $$
USE `bd_inventario`$$
CREATE
DEFINER=`root`@`localhost`
TRIGGER `bd_inventario`.`insumos_BEFORE_INSERT`
BEFORE INSERT ON `bd_inventario`.`insumos`
FOR EACH ROW
BEGIN	
	/*Checa que el Insumo No tenga mas de 10 Proveedores Asignados*/
    IF (	SELECT COUNT(*)>10
				FROM Insumos
				WHERE Id_insumo = new.id_insumo
				GROUP BY Id_insumo) >10 THEN
        SIGNAL SQLSTATE "45000"
        SET MESSAGE_TEXT = "No se puede Agregar mas de 10 Proveedores por Insumo";
	END IF;
END$$


